    if (cs1 == cs2) {
        return true;
    }
    if (cs1 == null || cs2 == null) {
        return false;
    }
    if (cs1 instanceof String && cs2 instanceof String) {
        return cs1.equals(cs2);
    }
    return cs1.length() == cs2.length()
            && CharSequenceUtils.regionMatches(cs1, false, 0, cs2, 0, cs1.length());
}

